def executeCommand():
    user_input = input().strip()
    if not user_input:
        return
    if re.search(r'[;&|`$()<>]', user_input):
        return
    try:
        args = shlex.split(user_input)
    except:
        return
    if not args:
        return
    try:
        subprocess.run(args, check=True)
    except subprocess.CalledProcessError:
